/**
 * 表示维度的一种类型。目前仅适用于原版维度。
 *
 * Represents a type of dimension. Currently only works with
 * Vanilla dimensions.
 */
export class DimensionType {
    private constructor();
    /**
     * @remarks
     * 维度类型的标识符。目前仅适用于原版维度。
     *
     * Identifier of the dimension type. Currently only works with
     * Vanilla dimensions.
     *
     */
    readonly typeId: string;
}
